INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Hyderabad', 'mess', 'Mess > Cost: Rs 130 per day. Semester mess expense is Rs 15,470 (130 x 119 days). Mid-semester break of 9 days is not counted (pay-per-meal during break).');
